#include<bits/stdc++.h> 
using namespace std;
long a[3005],cha[3005];
int main()
{
	int n;
	cin>>n;
	for(int i=0;i<=n-1;i++)
	{
		cin>>a[i];	
	}
	for(int i=0;i<=n-2;i++)
	{
		if(a[i]>a[i+1])
		{
			cha[i]=a[i]-a[i+1];
		}
		else
		{
			cha[i]=a[i+1]-a[i];	
		}
	}
	sort(cha,cha+n);
	for(int i=0;i<=n-2;i++)
	{
		if(cha[i+1]-cha[i]!=1)
		{
			cout<<"Not jolly";
			return 0;
		}
	}
	cout<<"Jolly";
	return 0;
}
